const raw = $input.first().json || {};
const now = new Date().toISOString();
const title = String(raw.titulo || raw.title || raw.assunto || 'entrada-sem-titulo').trim().slice(0, 160);
const content = String(raw.conteudo || raw.content || raw.texto || raw.message || '').trim();
const source = String(raw.origem || raw.source || 'webhook').trim();
const channel = String(raw.canal || raw.channel || source).trim();
const type = String(raw.tipo || raw.type || 'texto').trim();
const requestId = raw.request_id || `fbos_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

return [{ json: {
  request_id: requestId,
  received_at: now,
  title,
  content,
  source,
  channel,
  type,
  metadata: raw.metadata || {},
  raw_keys: Object.keys(raw),
  status: 'received',
  flags: []
}}];

const item = $input.first().json;
const flags = [...item.flags];
let valid = true;
let severity = 'baixo';

if (!item.content || item.content.length < 2) {
  valid = false;
  severity = 'medio';
  flags.push('conteudo_vazio');
}
if (item.content.length > 12000) {
  severity = 'medio';
  flags.push('conteudo_longo');
}
const secretPattern = /(sk-[A-Za-z0-9]{16,}|gh[pous]_[A-Za-z0-9]{16,}|Bearer\s+[A-Za-z0-9._-]{16,}|api[_-]?key\s*[:=]|password\s*[:=]|senha\s*[:=]|secret\s*[:=])/i;
if (secretPattern.test(item.content)) {
  severity = 'alto';
  flags.push('possivel_segredo');
}
const personalPattern = /(cpf|rg|cartao|cartão|endereco|endereço|telefone|whatsapp|email pessoal|saude|saúde)/i;
if (personalPattern.test(item.content)) {
  if (severity !== 'alto') severity = 'medio';
  flags.push('possivel_dado_pessoal');
}

return [{ json: { ...item, valid, severity, flags, status: valid ? 'validated' : 'rejected' } }];

const item = $input.first().json;
const text = `${item.title}\n${item.content}`.toLowerCase();
let domain = 'fabios';
let intent = 'captura';
let agent = 'agent.inbox';

const has = (...words) => words.some(w => text.includes(w));

if (has('prova', 'aluno', 'escola', 'professor', 'turma', 'pietra')) {
  domain = 'escolaos';
  intent = 'atendimento_escolar';
  agent = 'agent.inbox';
} else if (has('trade', 'trader', 'bitcoin', 'mercado', 'operacao')) {
  domain = 'traderos';
  intent = 'analise_trader';
  agent = 'agent.rag';
} else if (has('rag', 'fonte', 'consulta', 'pergunta')) {
  domain = 'rag';
  intent = 'consulta_semantica';
  agent = 'agent.rag';
} else if (has('commit', 'git', 'push', 'diff')) {
  domain = 'github';
  intent = 'pre_commit';
  agent = 'agent.safecommit';
} else if (has('arquivar', 'obsidian', 'nota', 'wiki')) {
  domain = 'llm_wiki';
  intent = 'arquivamento';
  agent = 'agent.arquivista';
} else if (has('dashboard', 'status', 'pendencia', 'tarefas')) {
  domain = 'governanca';
  intent = 'status_operacional';
  agent = 'agent.dashboard';
}

return [{ json: { ...item, domain, intent, suggested_agent: agent, status: 'classified' } }];

const item = $input.first().json;
let permission = 'propose_only';
let requiresApproval = true;
let blockedReason = null;

if (!item.valid) {
  permission = 'blocked';
  blockedReason = 'entrada_invalida';
}
if (item.flags.includes('possivel_segredo')) {
  permission = 'blocked';
  blockedReason = 'possivel_segredo';
}
if (item.intent === 'consulta_semantica') {
  permission = 'read_only';
  requiresApproval = false;
}
if (item.intent === 'pre_commit') {
  permission = 'propose_only';
  requiresApproval = true;
}
if (item.domain === 'escolaos' || item.flags.includes('possivel_dado_pessoal')) {
  permission = permission === 'blocked' ? permission : 'manual_approval';
  requiresApproval = true;
}

return [{ json: { ...item, permission, requires_approval: requiresApproval, blocked_reason: blockedReason, status: permission === 'blocked' ? 'blocked' : 'policy_checked' } }];

const item = $input.first().json;
let route = '00_Inbox/Triagem';
let action = 'triagem_manual';

if (item.permission === 'blocked') {
  route = '00_Inbox/Triagem/Bloqueados';
  action = 'bloquear_e_revisar';
} else if (item.suggested_agent === 'agent.arquivista') {
  route = '40_Wiki/_MOCs';
  action = 'preparar_nota_wiki';
} else if (item.suggested_agent === 'agent.rag') {
  route = '60_Sistemas/RAG';
  action = 'consulta_read_only';
} else if (item.suggested_agent === 'agent.safecommit') {
  route = '50_Registros/Auditoria';
  action = 'preflight_commit';
} else if (item.suggested_agent === 'agent.dashboard') {
  route = '10_Dashboard';
  action = 'atualizar_status_proposto';
}

return [{ json: { ...item, route, next_action: action, status: 'routed' } }];

const item = $input.first().json;
const audit = {
  request_id: item.request_id,
  received_at: item.received_at,
  domain: item.domain,
  intent: item.intent,
  agent: item.suggested_agent,
  permission: item.permission,
  route: item.route,
  next_action: item.next_action,
  flags: item.flags,
  external_effects: false,
  note: 'Workflow de orquestracao seguro: nenhum arquivo gravado e nenhuma API externa chamada.'
};
return [{ json: { ...item, audit, status: 'ready_to_respond' } }];
